// Some portions generated by Co-Pilot
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class StorePropertiesTest {

	@Test
	void saveAndLoadRoundTripsPersistedValues(@TempDir File dir) {
		StoreProperties properties = new StoreProperties(dir)
				.setVersion("1")
				.setTripleIndexes("spoc,posc");

		properties.save();

		StoreProperties loaded = new StoreProperties(dir);
		loaded.load();

		assertTrue(new File(dir, "store.properties").isFile());
		assertEquals("1", loaded.getVersion());
		assertEquals("spoc,posc", loaded.getTripleIndexes());
	}
}
